+            Subsystem::ModuleLoader,
+            Subsystem::HostcallGate,
+        ] {
+            let receipt = consumer.last_receipt_for(subsys).unwrap();
+            assert!(
+                receipt.decision.is_granted(),
+                "{subsys} should still be granted with critical assumptions"
+            );
+        }
+    }
